def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(1, a + 5):
                    coef = ((ratio - a) ** 6) / (a * b * 1.1 + 1)
                    priority += coef * np.sin(ratio * b / (a + 2)) * np.exp(-b / (a + 0.5))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2 + np.sqrt(ratio) * 4
            if i % 2 == 0:
                priority += np.log1p(bin_cap) * np.sin(i * ratio)
            else:
                priority -= np.tanh(bin_cap / (i + 1)) * 3
        elif 5 < ratio <= 8:
            for x in range(1, int(np.ceil(ratio)) + 5):
                for y in range(1, x + 4):
                    val = ((ratio - x) ** 4) * np.cos(ratio * x) / (y + 0.7)
                    priority += np.tanh(val) * 1.6
            priority += np.log(ratio) * 14 - np.tanh(ratio - 5) * 3.5
            if bin_cap < item * 1.2:
                priority += np.sqrt(item / (bin_cap + 1)) * 3.5
        elif 2 <= ratio <= 5:
            temp_sum = 0
            for r in range(1, 15):
                temp_sum += ((ratio - 2) ** r) / (r * 2.2) * np.sin(r * ratio * 1.1)
            priority = (temp_sum * np.cos(5.5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            for index in range(1, 6):
                priority += np.sin(index * ratio * i * 0.5) * ((ratio - 1.9) ** index) / (index + 0.5)
            if bin_cap > item * 2:
                priority -= np.exp(-1.2 * ratio) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5.5
            else:
                penalty = np.cos(15 * ratio) * 3.8
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.85) * ((ratio - 1) ** m) / (m + 0.8)
            if i % 5 == 0:
                priority += np.log1p(bin_cap) * 1.7
            else:
                priority -= np.tanh(bin_cap / (item + 0.2)) * 1.1
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 5) * np.sin(n * item * 0.9)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.9
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 1.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.9
            if bin_cap < item * 0.6:
                priority += np.log1p(item * bin_cap) * 3.7
            else:
                priority -= np.exp(-ratio * 2.2) * 2.5
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.3)
            priority = s + 2 / (bin_cap + 4)
            if int(item * 1.5) % 7 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.6
            else:
                priority -= np.exp(-ratio * 1.8) * 3.3
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.sin(item * m * 1.7)
        else:
            s = 0
            for t in range(1, 14):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.1
            else:
                priority -= np.exp(-ratio * 2.5) * 4.4
            for u in range(1, 11):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.sin(item * u * 0.95)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.1
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.25) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.25) * 0.75
        priorities[i] = priority
    return priorities
